-- Rename the column
ALTER TABLE skin_preferences 
  CHANGE COLUMN `graduatedToRealm` `graduatedToAxiom` tinyint(1) NOT NULL DEFAULT 0;

-- Fix the skin enum to include 'axiom' instead of 'apex'
ALTER TABLE skin_preferences 
  MODIFY COLUMN `skin` enum('axiom','hubspot','salesforce','pipedrive','zoho','gohighlevel','close') NOT NULL DEFAULT 'axiom';

-- Update any existing 'apex' values to 'axiom'
UPDATE skin_preferences SET skin = 'axiom' WHERE skin = 'apex';

-- Verify
SHOW COLUMNS FROM skin_preferences;

